import React, { useState, useRef, useEffect, useCallback } from 'react';
import './GeneratedComponent.css';

interface GeneratedComponentProps {
  id: string;
  code: string;
  position: { x: number; y: number };
  size: { width: number; height: number };
  isSelected: boolean;
  onSelect: (id: string) => void;
  onResize: (id: string, width: number, height: number) => void;
  onMove: (id: string, x: number, y: number) => void;
  onEdit?: (id: string) => void;
  onDelete?: (id: string) => void;
  onDuplicate?: (id: string) => void;
}

type ResizeDirection = 'n' | 's' | 'e' | 'w' | 'ne' | 'nw' | 'se' | 'sw';

interface DragState {
  isDragging: boolean;
  isResizing: boolean;
  resizeDirection?: ResizeDirection;
  startPos: { x: number; y: number };
  startSize: { width: number; height: number };
  startMouse: { x: number; y: number };
}

const GeneratedComponent: React.FC<GeneratedComponentProps> = ({
  id,
  code,
  position,
  size,
  isSelected,
  onSelect,
  onResize,
  onMove,
  onEdit,
  onDelete,
  onDuplicate
}) => {
  const [dragState, setDragState] = useState<DragState>({
    isDragging: false,
    isResizing: false,
    startPos: { x: 0, y: 0 },
    startSize: { width: 0, height: 0 },
    startMouse: { x: 0, y: 0 }
  });

  const [showContextMenu, setShowContextMenu] = useState(false);
  const [contextMenuPosition, setContextMenuPosition] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);

  const componentRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);

  // Minimum size constraints
  const MIN_WIDTH = 100;
  const MIN_HEIGHT = 80;

  // Handle mouse down for dragging
  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    e.stopPropagation();
    onSelect(id);
    setShowContextMenu(false);

    // Only start dragging if clicking on the component itself, not resize handles
    if (e.target === componentRef.current || e.target === contentRef.current || 
        (e.target as HTMLElement).closest('.component-content')) {
      setDragState({
        isDragging: true,
        isResizing: false,
        startPos: position,
        startSize: size,
        startMouse: { x: e.clientX, y: e.clientY }
      });
    }
  }, [id, onSelect, position, size]);

  // Handle resize start
  const handleResizeStart = useCallback((e: React.MouseEvent, direction: ResizeDirection) => {
    e.stopPropagation();
    e.preventDefault();

    setDragState({
      isDragging: false,
      isResizing: true,
      resizeDirection: direction,
      startPos: position,
      startSize: size,
      startMouse: { x: e.clientX, y: e.clientY }
    });
  }, [position, size]);

  // Handle context menu
  const handleContextMenu = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    onSelect(id);
    setContextMenuPosition({ x: e.clientX, y: e.clientY });
    setShowContextMenu(true);
  }, [id, onSelect]);

  // Mouse move handler
  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (dragState.isDragging) {
      const deltaX = e.clientX - dragState.startMouse.x;
      const deltaY = e.clientY - dragState.startMouse.y;

      onMove(id, dragState.startPos.x + deltaX, dragState.startPos.y + deltaY);
    } else if (dragState.isResizing && dragState.resizeDirection) {
      const deltaX = e.clientX - dragState.startMouse.x;
      const deltaY = e.clientY - dragState.startMouse.y;

      let newWidth = dragState.startSize.width;
      let newHeight = dragState.startSize.height;
      let newX = dragState.startPos.x;
      let newY = dragState.startPos.y;

      const direction = dragState.resizeDirection;

      // Handle width changes
      if (direction.includes('e')) {
        newWidth = Math.max(MIN_WIDTH, dragState.startSize.width + deltaX);
      } else if (direction.includes('w')) {
        const widthChange = -deltaX;
        newWidth = Math.max(MIN_WIDTH, dragState.startSize.width + widthChange);
        if (newWidth > MIN_WIDTH) {
          newX = dragState.startPos.x - widthChange;
        }
      }

      // Handle height changes
      if (direction.includes('s')) {
        newHeight = Math.max(MIN_HEIGHT, dragState.startSize.height + deltaY);
      } else if (direction.includes('n')) {
        const heightChange = -deltaY;
        newHeight = Math.max(MIN_HEIGHT, dragState.startSize.height + heightChange);
        if (newHeight > MIN_HEIGHT) {
          newY = dragState.startPos.y - heightChange;
        }
      }

      // Update position if needed (for northwest, west, north, northeast resize)
      if (newX !== dragState.startPos.x || newY !== dragState.startPos.y) {
        onMove(id, newX, newY);
      }

      onResize(id, newWidth, newHeight);
    }
  }, [dragState, id, onMove, onResize]);

  // Mouse up handler
  const handleMouseUp = useCallback(() => {
    setDragState({
      isDragging: false,
      isResizing: false,
      startPos: { x: 0, y: 0 },
      startSize: { width: 0, height: 0 },
      startMouse: { x: 0, y: 0 }
    });
  }, []);

  // Add/remove event listeners
  useEffect(() => {
    if (dragState.isDragging || dragState.isResizing) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = dragState.isDragging ? 'grabbing' : 'inherit';

      return () => {
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
        document.body.style.cursor = 'inherit';
      };
    }
  }, [dragState.isDragging, dragState.isResizing, handleMouseMove, handleMouseUp]);

  // Close context menu on outside click
  useEffect(() => {
    const handleClickOutside = () => setShowContextMenu(false);
    if (showContextMenu) {
      document.addEventListener('click', handleClickOutside);
      return () => document.removeEventListener('click', handleClickOutside);
    }
  }, [showContextMenu]);

  // Render generated content safely
  const renderGeneratedContent = () => {
    try {
      return (
        <div 
          className="generated-content"
          dangerouslySetInnerHTML={{ __html: code }}
        />
      );
    } catch (error) {
      return (
        <div className="error-content">
          <div className="error-icon">⚠️</div>
          <p>Error rendering component</p>
        </div>
      );
    }
  };

  // Context menu handlers
  const handleEdit = () => {
    setShowContextMenu(false);
    onEdit && onEdit(id);
  };

  const handleDuplicate = () => {
    setShowContextMenu(false);
    onDuplicate && onDuplicate(id);
  };

  const handleDelete = () => {
    setShowContextMenu(false);
    onDelete && onDelete(id);
  };

  return (
    <>
      <div
        ref={componentRef}
        className={`generated-component ${isSelected ? 'selected' : ''} ${isHovered ? 'hovered' : ''}`}
        style={{
          left: position.x,
          top: position.y,
          width: size.width,
          height: size.height,
        }}
        onMouseDown={handleMouseDown}
        onContextMenu={handleContextMenu}
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
      >
        {/* Selection Frame */}
        {isSelected && (
          <div className="selection-frame">
            {/* Component Label */}
            <div className="component-label">
              <span className="component-icon">📱</span>
              <span>Component {id.slice(-3)}</span>
            </div>

            {/* Size Display */}
            <div className="size-display">
              {Math.round(size.width)} × {Math.round(size.height)}
            </div>
          </div>
        )}

        {/* Component Content */}
        <div ref={contentRef} className="component-content">
          {renderGeneratedContent()}
        </div>

        {/* Transform Handles */}
        {isSelected && (
          <div className="transform-handles">
            {/* Corner handles */}
            <div 
              className="handle corner nw-handle" 
              onMouseDown={(e) => handleResizeStart(e, 'nw')}
            />
            <div 
              className="handle corner ne-handle" 
              onMouseDown={(e) => handleResizeStart(e, 'ne')}
            />
            <div 
              className="handle corner sw-handle" 
              onMouseDown={(e) => handleResizeStart(e, 'sw')}
            />
            <div 
              className="handle corner se-handle" 
              onMouseDown={(e) => handleResizeStart(e, 'se')}
            />

            {/* Edge handles */}
            <div 
              className="handle edge n-handle" 
              onMouseDown={(e) => handleResizeStart(e, 'n')}
            />
            <div 
              className="handle edge s-handle" 
              onMouseDown={(e) => handleResizeStart(e, 's')}
            />
            <div 
              className="handle edge w-handle" 
              onMouseDown={(e) => handleResizeStart(e, 'w')}
            />
            <div 
              className="handle edge e-handle" 
              onMouseDown={(e) => handleResizeStart(e, 'e')}
            />
          </div>
        )}

        {/* Bounding Box Border */}
        {(isSelected || isHovered) && (
          <div className={`bounding-box ${isSelected ? 'selected' : 'hovered'}`} />
        )}
      </div>

      {/* Context Menu */}
      {showContextMenu && (
        <div 
          className="context-menu"
          style={{
            position: 'fixed',
            left: contextMenuPosition.x,
            top: contextMenuPosition.y,
            zIndex: 10000
          }}
        >
          <div className="context-menu-item" onClick={handleEdit}>
            <span className="context-icon">✏️</span>
            Edit Component
          </div>
          <div className="context-menu-item" onClick={handleDuplicate}>
            <span className="context-icon">📋</span>
            Duplicate
          </div>
          <div className="context-menu-divider" />
          <div className="context-menu-item danger" onClick={handleDelete}>
            <span className="context-icon">🗑️</span>
            Delete
          </div>
        </div>
      )}
    </>
  );
};

export default GeneratedComponent;
